class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False
        diff = [0] * 26
        for i in range(len(s)):
            if s[i] != t[i]:
                shift = (ord(t[i]) - ord(s[i])) % 26
                diff[shift] += 1
        total_moves = 0
        for i in range(1, 26):
            total_moves += (i * diff[i])
            if total_moves > k:
                return False
        return True
